FILES = {'src/frontend/command_center/modern/claire_dashboard_reset_v17_62_5.css': '/*\n  Claire v17.62.5 — Dashboard Conflict Cleanup + Stable Runtime Stack\n\n  This is a cleanup/reset hotfix for the v17.62 layout chain.\n  It disables conflicting generated panels/search overlays and replaces them\n  with one clean, readable runtime-truth stack.\n\n  Runtime logic unchanged.\n*/\n\n:root {\n  --claire-reset-border: rgba(0, 212, 255, 0.22);\n  --claire-reset-bg: rgba(7, 14, 27, 0.86);\n  --claire-reset-card: rgba(12, 20, 36, 0.78);\n  --claire-reset-text: #d9e5f3;\n  --claire-reset-muted: #93a4ba;\n  --claire-reset-cyan: #00d4ff;\n  --claire-reset-purple: #c084fc;\n  --claire-reset-amber: #f59e0b;\n  --claire-reset-green: #22c55e;\n}\n\n/* Remove the old floating/duplicated search shells and bridge panels. */\n.claire-old-ui-hidden,\n#claire-validation-authority-panel.claire-old-ui-hidden,\n#claire-verified-memory-panel.claire-old-ui-hidden,\n#claire-search-json-result-panel.claire-old-ui-hidden {\n  display: none !important;\n  visibility: hidden !important;\n  pointer-events: none !important;\n}\n\n/* Hard remove top-overlay search from old v17.62 layers. */\nbody .claire-dashboard-search-shell:not(#claire-clean-search-shell),\nbody #claire-dashboard-search-shell:not(#claire-clean-search-shell) {\n  display: none !important;\n  visibility: hidden !important;\n  pointer-events: none !important;\n}\n\n/* Base workspace normalization. */\nhtml, body {\n  min-height: 100% !important;\n  overflow-x: hidden !important;\n}\n\nbody {\n  overflow-y: auto !important;\n}\n\nmain,\n#app,\n#workspace,\n#main-workspace,\n.command-center,\n.operating-environment,\n.claire-operating-environment,\n.claire-shell,\n.dashboard-shell {\n  height: auto !important;\n  min-height: 0 !important;\n  max-height: none !important;\n  overflow: visible !important;\n}\n\n/* Let right and left rails scroll independently, but do not let them control center height. */\n.nav-sidebar,\n.side-nav,\n.sidebar,\naside[class*="side"] {\n  max-height: calc(100vh - 24px) !important;\n  overflow-y: auto !important;\n  overflow-x: hidden !important;\n}\n\n.live-rail,\n.right-rail,\n.narrative-rail,\naside[class*="rail"],\nsection[class*="rail"] {\n  max-height: calc(100vh - 160px) !important;\n  overflow-y: auto !important;\n  overflow-x: hidden !important;\n}\n\n/* Clean search embedded in the Claire identity/sidebar area. */\n#claire-clean-search-shell {\n  position: relative !important;\n  top: auto !important;\n  left: auto !important;\n  right: auto !important;\n  transform: none !important;\n  width: 100% !important;\n  margin: 16px 0 10px 0 !important;\n  z-index: 50 !important;\n  color: var(--claire-reset-text);\n  font-family: Inter, system-ui, sans-serif;\n}\n\n.claire-clean-search-box {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  min-height: 46px;\n  border: 1px solid rgba(0, 212, 255, 0.30);\n  border-radius: 16px;\n  padding: 8px 10px;\n  background: rgba(2, 10, 20, 0.78);\n  box-shadow: inset 0 0 18px rgba(0, 212, 255, 0.04), 0 0 20px rgba(0, 212, 255, 0.08);\n}\n\n.claire-clean-search-input {\n  flex: 1;\n  min-width: 0;\n  border: 0;\n  outline: 0;\n  background: transparent;\n  color: #f8fafc;\n  font-size: 12px;\n  line-height: 1.35;\n}\n\n.claire-clean-search-input::placeholder {\n  color: #69758a;\n}\n\n.claire-clean-mic {\n  width: 34px;\n  height: 34px;\n  flex: 0 0 34px;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  border: 1px solid rgba(0, 212, 255, 0.28);\n  border-radius: 999px;\n  color: var(--claire-reset-cyan);\n  background: rgba(0, 212, 255, 0.08);\n  cursor: pointer;\n}\n\n.claire-clean-mic.listening {\n  color: var(--claire-reset-green);\n  border-color: rgba(34, 197, 94, 0.72);\n  background: rgba(34, 197, 94, 0.12);\n}\n\n.claire-clean-mic[disabled] {\n  opacity: 0.45;\n  cursor: not-allowed;\n}\n\n.claire-clean-search-results {\n  display: none;\n  position: absolute;\n  left: 0;\n  right: 0;\n  top: calc(100% + 8px);\n  z-index: 10080;\n  border: 1px solid rgba(0, 212, 255, 0.24);\n  border-radius: 16px;\n  background: rgba(3, 8, 18, 0.97);\n  backdrop-filter: blur(18px);\n  box-shadow: 0 22px 52px rgba(0, 0, 0, 0.34);\n  max-height: min(62vh, 520px);\n  overflow: auto;\n  padding: 8px;\n}\n\n.claire-clean-search-results.open {\n  display: block;\n}\n\n.claire-clean-result {\n  display: block;\n  width: 100%;\n  text-align: left;\n  border: 1px solid rgba(148, 163, 184, 0.12);\n  border-radius: 14px;\n  padding: 10px 12px;\n  margin: 6px 0;\n  background: rgba(15, 23, 42, 0.52);\n  color: #e2e8f0;\n  cursor: pointer;\n}\n\n.claire-clean-result:hover,\n.claire-clean-result.active {\n  border-color: rgba(0, 212, 255, 0.45);\n  background: rgba(0, 212, 255, 0.08);\n}\n\n.claire-clean-result-title {\n  color: #f8fafc;\n  font-weight: 800;\n  font-size: 12px;\n  line-height: 1.4;\n  overflow-wrap: anywhere;\n}\n\n.claire-clean-result-meta {\n  margin-top: 2px;\n  color: #7dd3fc;\n  font-size: 10px;\n  letter-spacing: .06em;\n  text-transform: uppercase;\n  overflow-wrap: anywhere;\n}\n\n.claire-clean-result-snippet {\n  margin-top: 6px;\n  color: #94a3b8;\n  font-size: 12px;\n  line-height: 1.5;\n  overflow-wrap: anywhere;\n}\n\n/* Hide the old intro text only after the new slot is installed. */\n.claire-clean-intro-hidden {\n  display: none !important;\n}\n\n/* Clean main truth stack. */\n#claire-clean-runtime-stack {\n  position: relative !important;\n  display: block !important;\n  width: 100% !important;\n  clear: both !important;\n  margin: 22px 0 26px 0 !important;\n  padding: 0 !important;\n  z-index: 3 !important;\n}\n\n.claire-clean-stack-section {\n  position: relative !important;\n  display: block !important;\n  width: 100% !important;\n  height: auto !important;\n  min-height: 0 !important;\n  max-height: none !important;\n  overflow: visible !important;\n  margin: 0 0 18px 0 !important;\n  padding: 22px !important;\n  border: 1px solid var(--claire-reset-border);\n  border-radius: 22px;\n  background: linear-gradient(135deg, rgba(7, 14, 27, 0.94), rgba(10, 18, 34, 0.86));\n  box-shadow: 0 0 26px rgba(0, 212, 255, 0.06);\n}\n\n.claire-clean-stack-section.purple {\n  border-color: rgba(192, 132, 252, 0.30);\n  background: linear-gradient(135deg, rgba(13, 9, 28, 0.94), rgba(22, 14, 39, 0.86));\n  box-shadow: 0 0 26px rgba(192, 132, 252, 0.06);\n}\n\n.claire-clean-stack-header {\n  display: flex;\n  align-items: flex-start;\n  justify-content: space-between;\n  gap: 14px;\n  margin-bottom: 16px;\n  flex-wrap: wrap;\n}\n\n.claire-clean-stack-kicker {\n  font-family: Orbitron, Inter, system-ui, sans-serif;\n  font-size: 11px;\n  font-weight: 800;\n  letter-spacing: .16em;\n  text-transform: uppercase;\n  color: var(--claire-reset-cyan);\n  margin-bottom: 6px;\n}\n\n.claire-clean-stack-section.purple .claire-clean-stack-kicker {\n  color: var(--claire-reset-purple);\n}\n\n.claire-clean-stack-title {\n  font-family: Orbitron, Inter, system-ui, sans-serif;\n  color: #f2f8ff;\n  font-size: clamp(18px, 1.5vw, 24px);\n  font-weight: 800;\n  letter-spacing: .06em;\n  line-height: 1.25;\n}\n\n.claire-clean-stack-subtitle {\n  color: var(--claire-reset-muted);\n  font-size: 13px;\n  line-height: 1.55;\n  margin-top: 5px;\n  max-width: 760px;\n}\n\n.claire-clean-pill {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  min-width: 92px;\n  width: auto;\n  height: auto;\n  border-radius: 999px;\n  padding: 8px 12px;\n  font-size: 11px;\n  font-weight: 800;\n  line-height: 1.2;\n  letter-spacing: .08em;\n  text-transform: uppercase;\n  border: 1px solid rgba(148, 163, 184, 0.28);\n  color: #cbd5e1;\n  background: rgba(148, 163, 184, 0.06);\n  white-space: normal;\n}\n\n.claire-clean-pill.pass,\n.claire-clean-pill.eligible,\n.claire-clean-pill.allowed,\n.claire-clean-pill.loaded {\n  color: var(--claire-reset-green);\n  border-color: rgba(34, 197, 94, 0.42);\n  background: rgba(34, 197, 94, 0.08);\n}\n\n.claire-clean-pill.warning,\n.claire-clean-pill.not_generated,\n.claire-clean-pill.not_loaded,\n.claire-clean-pill.missing {\n  color: var(--claire-reset-amber);\n  border-color: rgba(245, 158, 11, 0.42);\n  background: rgba(245, 158, 11, 0.08);\n}\n\n.claire-clean-pill.fail,\n.claire-clean-pill.blocked {\n  color: #f87171;\n  border-color: rgba(248, 113, 113, 0.42);\n  background: rgba(248, 113, 113, 0.08);\n}\n\n.claire-clean-grid {\n  display: grid !important;\n  grid-template-columns: repeat(auto-fit, minmax(210px, 1fr)) !important;\n  gap: 12px !important;\n  align-items: stretch !important;\n}\n\n.claire-clean-card {\n  position: relative !important;\n  height: auto !important;\n  min-height: 96px !important;\n  max-height: none !important;\n  overflow: visible !important;\n  border: 1px solid rgba(148, 163, 184, 0.16);\n  border-radius: 16px;\n  background: rgba(15, 23, 42, 0.48);\n  padding: 14px !important;\n}\n\n.claire-clean-label {\n  color: #91a0b6;\n  font-size: 10px;\n  letter-spacing: .12em;\n  text-transform: uppercase;\n  margin-bottom: 7px;\n}\n\n.claire-clean-value {\n  color: #f8fafc;\n  font-size: 16px;\n  font-weight: 900;\n  line-height: 1.35;\n  overflow-wrap: anywhere;\n}\n\n.claire-clean-note {\n  margin-top: 10px;\n  color: #a8b5c8;\n  font-size: 12px;\n  line-height: 1.55;\n  overflow-wrap: anywhere;\n}\n\n.claire-clean-wide {\n  grid-column: 1 / -1;\n}\n\n/* Neutralize major old overlap causes in command area. */\n.claire-clean-command-repaired,\n.claire-clean-command-repaired * {\n  max-height: none !important;\n}\n\n.claire-clean-command-repaired {\n  position: relative !important;\n  height: auto !important;\n  min-height: 220px !important;\n  overflow: visible !important;\n  margin-bottom: 22px !important;\n  padding-bottom: 22px !important;\n  z-index: 2 !important;\n}\n\n.claire-clean-command-repaired [style*="overflow"],\n.claire-clean-command-repaired [style*="max-height"],\n.claire-clean-command-repaired [style*="height"] {\n  overflow: visible !important;\n  max-height: none !important;\n  height: auto !important;\n}\n\n/* Avoid the bottom proofbar becoming a cross-page overlay. */\n.proofbar,\n.status-rail,\n.bottom-rail,\n.claire-proofbar,\n[class*="proofbar"] {\n  position: relative !important;\n  clear: both !important;\n  z-index: 2 !important;\n}\n\n/* Focus button stays available but does not dominate. */\n.claire-view-mode-toggle {\n  position: fixed !important;\n  top: 18px !important;\n  right: 18px !important;\n  z-index: 10010 !important;\n}\n\n/* Mobile/smaller widths. */\n@media (max-width: 920px) {\n  .claire-clean-search-results {\n    position: relative;\n    top: auto;\n    margin-top: 8px;\n  }\n\n  .claire-clean-grid {\n    grid-template-columns: 1fr !important;\n  }\n\n  .claire-clean-stack-section {\n    padding: 16px !important;\n  }\n}\n', 'src/frontend/command_center/modern/claire_dashboard_reset_v17_62_5.js': '(function () {\n  "use strict";\n\n  const JSON_PATHS = [\n    "dashboard_search_index.json",\n    "dashboard_architecture_map.json",\n    "lifecycle_stage_registry.json",\n    "runtime_surface_registry.json",\n    "route_surface_registry.json",\n    "runtime_truth_status.json",\n    "validation_authority_status.json",\n    "evidence_traceability_status.json",\n    "verified_memory_status.json",\n    "recursive_feedback_status.json",\n    "../../../exports/latest/dashboard_runtime_truth.json",\n    "../../../exports/latest/validation_authority_report.json",\n    "../../../exports/latest/evidence_traceability_index.json",\n    "../../../exports/latest/verified_memory_gate_report.json",\n    "../../../exports/latest/recursive_feedback_gate_report.json",\n    "exports/latest/dashboard_runtime_truth.json",\n    "exports/latest/validation_authority_report.json",\n    "exports/latest/evidence_traceability_index.json",\n    "exports/latest/verified_memory_gate_report.json",\n    "exports/latest/recursive_feedback_gate_report.json"\n  ];\n\n  const state = {\n    docs: [],\n    selectedIndex: -1,\n    listening: false,\n    recognition: null\n  };\n\n  function normalize(value) {\n    return String(value ?? "").replace(/\\s+/g, " ").trim();\n  }\n\n  function lower(value) {\n    return normalize(value).toLowerCase();\n  }\n\n  function escapeHtml(value) {\n    return String(value ?? "")\n      .replace(/&/g, "&amp;")\n      .replace(/</g, "&lt;")\n      .replace(/>/g, "&gt;")\n      .replace(/"/g, "&quot;");\n  }\n\n  function flattenJson(value, prefix = "") {\n    const rows = [];\n    function walk(node, path) {\n      if (node === null || node === undefined) return;\n      if (Array.isArray(node)) {\n        node.forEach((item, index) => walk(item, `${path}[${index}]`));\n        return;\n      }\n      if (typeof node === "object") {\n        Object.entries(node).forEach(([key, item]) => walk(item, path ? `${path}.${key}` : key));\n        return;\n      }\n      rows.push(`${path}: ${String(node)}`);\n    }\n    walk(value, prefix);\n    return rows.join("\\n");\n  }\n\n  async function fetchJson(path) {\n    try {\n      const response = await fetch(path, { cache: "no-store" });\n      if (!response.ok) return null;\n      return await response.json();\n    } catch (_) {\n      return null;\n    }\n  }\n\n  async function fetchFirst(paths) {\n    for (const path of paths) {\n      const json = await fetchJson(path);\n      if (json) return { path, json };\n    }\n    return { path: "", json: null };\n  }\n\n  function first(obj, keys, fallback = "") {\n    if (!obj || typeof obj !== "object") return fallback;\n    for (const key of keys) {\n      const value = obj[key];\n      if (value !== undefined && value !== null && value !== "") return value;\n    }\n    return fallback;\n  }\n\n  function section(obj, key) {\n    const value = obj?.[key];\n    return value && typeof value === "object" && !Array.isArray(value) ? value : {};\n  }\n\n  function compactStatus(value) {\n    return lower(value || "not_generated").replace(/\\s+/g, "_");\n  }\n\n  function addDoc(doc) {\n    const key = `${doc.type}:${doc.path}:${doc.title}`;\n    if (state.docs.some((existing) => `${existing.type}:${existing.path}:${existing.title}` === key)) return;\n    state.docs.push(doc);\n  }\n\n  function collectVisibleDocs() {\n    const nodes = Array.from(document.querySelectorAll(\n      "section,article,.dashboard-panel,.claire-panel,.surface,.claire-surface,.portal,.claire-portal,.stage-card,.route-col,.validation-node,.roadmap-card,#claire-clean-runtime-stack"\n    ));\n\n    nodes.forEach((node, index) => {\n      if (!node || node.classList.contains("claire-old-ui-hidden")) return;\n      if (node.closest("#claire-clean-search-shell")) return;\n\n      const text = normalize(node.innerText || node.textContent || "");\n      if (text.length < 20) return;\n\n      if (!node.id) node.id = `claire-clean-search-section-${index + 1}`;\n\n      const titleNode = node.querySelector("h1,h2,h3,.section-title,.claire-clean-stack-title");\n      addDoc({\n        type: "visible_surface",\n        title: normalize(titleNode?.innerText || titleNode?.textContent || node.id),\n        path: `#${node.id}`,\n        text,\n        targetId: node.id\n      });\n    });\n  }\n\n  async function collectJsonDocs() {\n    for (const path of [...new Set(JSON_PATHS)]) {\n      const json = await fetchJson(path);\n      if (!json) continue;\n\n      if (json.schema === "claire.dashboard_intelligence_index.v1" && Array.isArray(json.documents)) {\n        for (const doc of json.documents) {\n          if (doc.status && doc.status !== "indexed") continue;\n          addDoc({\n            type: "dashboard_index",\n            title: doc.title || doc.path || path,\n            path: doc.path || path,\n            text: doc.text || (Array.isArray(doc.terms) ? doc.terms.join(" ") : ""),\n            json: doc\n          });\n        }\n      }\n\n      addDoc({\n        type: "runtime_or_contract_json",\n        title: path.split("/").pop() || path,\n        path,\n        text: flattenJson(json),\n        json\n      });\n    }\n  }\n\n  function score(doc, parts) {\n    const haystack = `${doc.title}\\n${doc.path}\\n${doc.text}`.toLowerCase();\n    let value = 0;\n    for (const part of parts) {\n      if (doc.title.toLowerCase().includes(part)) value += 14;\n      if (doc.path.toLowerCase().includes(part)) value += 7;\n      value += Math.min(haystack.split(part).length - 1, 14);\n    }\n    return value;\n  }\n\n  function snippet(text, parts) {\n    const clean = normalize(text);\n    const hay = clean.toLowerCase();\n    let idx = -1;\n    for (const part of parts) {\n      idx = hay.indexOf(part);\n      if (idx >= 0) break;\n    }\n    if (idx < 0) return clean.slice(0, 220);\n    const start = Math.max(0, idx - 80);\n    const end = Math.min(clean.length, idx + 180);\n    return `${start > 0 ? "…" : ""}${clean.slice(start, end)}${end < clean.length ? "…" : ""}`;\n  }\n\n  function search(query) {\n    const parts = lower(query).split(" ").filter(Boolean);\n    if (!parts.length) return [];\n    return state.docs\n      .map((doc) => ({ doc, score: score(doc, parts), snippet: snippet(doc.text, parts) }))\n      .filter((item) => item.score > 0)\n      .sort((a, b) => b.score - a.score)\n      .slice(0, 12);\n  }\n\n  function findIntroText() {\n    const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT);\n    let node;\n    const patterns = [\n      "operating environment aligned",\n      "complete systems flow map",\n      "runtime truth first",\n      "no fake run data"\n    ];\n\n    while ((node = walker.nextNode())) {\n      const text = lower(node.nodeValue);\n      if (patterns.some((pattern) => text.includes(pattern))) {\n        return node.parentElement;\n      }\n    }\n    return null;\n  }\n\n  function findBrandMount() {\n    const existing = document.getElementById("claire-clean-search-slot");\n    if (existing) return existing;\n\n    const intro = findIntroText();\n    if (intro) {\n      intro.classList.add("claire-clean-intro-hidden");\n      const slot = document.createElement("div");\n      slot.id = "claire-clean-search-slot";\n      intro.insertAdjacentElement("afterend", slot);\n      return slot;\n    }\n\n    const candidates = Array.from(document.querySelectorAll("aside,nav,header,.sidebar,.side-nav,.brand,.identity,div"));\n    for (const node of candidates) {\n      const text = lower(node.innerText || node.textContent || "");\n      if (text.includes("claire syntalion") || text.includes("claire")) {\n        const slot = document.createElement("div");\n        slot.id = "claire-clean-search-slot";\n        node.appendChild(slot);\n        return slot;\n      }\n    }\n\n    const slot = document.createElement("div");\n    slot.id = "claire-clean-search-slot";\n    document.body.prepend(slot);\n    return slot;\n  }\n\n  function micIcon() {\n    return `\n      <svg width="17" height="17" viewBox="0 0 24 24" fill="none" aria-hidden="true">\n        <path d="M12 14a3 3 0 0 0 3-3V6a3 3 0 1 0-6 0v5a3 3 0 0 0 3 3Z" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>\n        <path d="M19 11a7 7 0 0 1-14 0" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>\n        <path d="M12 18v4" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>\n        <path d="M8 22h8" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>\n      </svg>\n    `;\n  }\n\n  function removeConflictingUi() {\n    document.querySelectorAll(".claire-dashboard-search-shell,#claire-dashboard-search-shell").forEach((node) => {\n      if (node.id !== "claire-clean-search-shell") node.remove();\n    });\n\n    [\n      "#claire-validation-authority-panel",\n      "#claire-verified-memory-panel",\n      "#claire-search-json-result-panel"\n    ].forEach((selector) => {\n      document.querySelectorAll(selector).forEach((node) => {\n        node.classList.add("claire-old-ui-hidden");\n      });\n    });\n  }\n\n  function renderSearch() {\n    removeConflictingUi();\n\n    const old = document.getElementById("claire-clean-search-shell");\n    if (old) old.remove();\n\n    const mount = findBrandMount();\n    const shell = document.createElement("div");\n    shell.id = "claire-clean-search-shell";\n    shell.innerHTML = `\n      <div class="claire-clean-search-box">\n        <input id="claire-clean-search-input" class="claire-clean-search-input" autocomplete="off" spellcheck="false" placeholder="Search or ask Claire…" aria-label="Claire dashboard search" />\n        <button id="claire-clean-mic" class="claire-clean-mic" type="button" aria-label="Use microphone">${micIcon()}</button>\n      </div>\n      <div id="claire-clean-search-results" class="claire-clean-search-results" role="listbox"></div>\n    `;\n    mount.appendChild(shell);\n\n    const input = document.getElementById("claire-clean-search-input");\n    const results = document.getElementById("claire-clean-search-results");\n    const mic = document.getElementById("claire-clean-mic");\n\n    input.addEventListener("input", () => {\n      const query = input.value.trim();\n      state.selectedIndex = -1;\n      if (!query) {\n        results.classList.remove("open");\n        results.innerHTML = "";\n        return;\n      }\n      renderSearchResults(search(query));\n    });\n\n    input.addEventListener("focus", () => {\n      if (input.value.trim()) renderSearchResults(search(input.value));\n    });\n\n    input.addEventListener("keydown", (event) => {\n      const buttons = Array.from(results.querySelectorAll(".claire-clean-result"));\n      if (event.key === "Escape") {\n        results.classList.remove("open");\n        input.blur();\n      } else if (event.key === "ArrowDown" && buttons.length) {\n        event.preventDefault();\n        state.selectedIndex = Math.min(buttons.length - 1, state.selectedIndex + 1);\n        markActive(buttons);\n      } else if (event.key === "ArrowUp" && buttons.length) {\n        event.preventDefault();\n        state.selectedIndex = Math.max(0, state.selectedIndex - 1);\n        markActive(buttons);\n      } else if (event.key === "Enter" && state.selectedIndex >= 0 && buttons[state.selectedIndex]) {\n        event.preventDefault();\n        buttons[state.selectedIndex].click();\n      }\n    });\n\n    document.addEventListener("keydown", (event) => {\n      const isMac = navigator.platform.toUpperCase().includes("MAC");\n      if ((isMac ? event.metaKey : event.ctrlKey) && event.key.toLowerCase() === "k") {\n        event.preventDefault();\n        input.focus();\n        input.select();\n      }\n    });\n\n    document.addEventListener("click", (event) => {\n      if (!shell.contains(event.target)) results.classList.remove("open");\n    });\n\n    setupMic(input, mic);\n  }\n\n  function setupMic(input, mic) {\n    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;\n    if (!SpeechRecognition) {\n      mic.disabled = true;\n      mic.title = "Microphone search is not supported in this browser.";\n      return;\n    }\n\n    const recognition = new SpeechRecognition();\n    state.recognition = recognition;\n    recognition.continuous = false;\n    recognition.interimResults = false;\n    recognition.lang = navigator.language || "en-US";\n\n    recognition.onstart = () => {\n      state.listening = true;\n      mic.classList.add("listening");\n      input.placeholder = "Listening…";\n    };\n\n    recognition.onend = () => {\n      state.listening = false;\n      mic.classList.remove("listening");\n      input.placeholder = "Search or ask Claire…";\n    };\n\n    recognition.onerror = () => {\n      state.listening = false;\n      mic.classList.remove("listening");\n      input.placeholder = "Search or ask Claire…";\n    };\n\n    recognition.onresult = (event) => {\n      const transcript = Array.from(event.results || [])\n        .map((result) => result[0]?.transcript || "")\n        .join(" ")\n        .trim();\n      if (transcript) {\n        input.value = transcript;\n        input.dispatchEvent(new Event("input", { bubbles: true }));\n        input.focus();\n      }\n    };\n\n    mic.addEventListener("click", () => {\n      try {\n        if (state.listening) recognition.stop();\n        else recognition.start();\n      } catch (_) {}\n    });\n  }\n\n  function markActive(buttons) {\n    buttons.forEach((button, index) => {\n      button.classList.toggle("active", index === state.selectedIndex);\n      if (index === state.selectedIndex) button.scrollIntoView({ block: "nearest" });\n    });\n  }\n\n  function renderSearchResults(items) {\n    const results = document.getElementById("claire-clean-search-results");\n    if (!results) return;\n    results.classList.add("open");\n\n    if (!items.length) {\n      results.innerHTML = `<div class="claire-clean-result-snippet" style="padding:12px;">No local dashboard/runtime matches. Generate truth, validation, memory, and index reports if this data should exist.</div>`;\n      return;\n    }\n\n    results.innerHTML = items.map((item, index) => `\n      <button class="claire-clean-result" type="button" data-index="${index}">\n        <div class="claire-clean-result-title">${escapeHtml(item.doc.title)}</div>\n        <div class="claire-clean-result-meta">${escapeHtml(item.doc.type)} · ${escapeHtml(item.doc.path)}</div>\n        <div class="claire-clean-result-snippet">${escapeHtml(item.snippet)}</div>\n      </button>\n    `).join("");\n\n    Array.from(results.querySelectorAll(".claire-clean-result")).forEach((button, index) => {\n      button.addEventListener("click", () => openResult(items[index].doc));\n    });\n  }\n\n  function openResult(doc) {\n    const results = document.getElementById("claire-clean-search-results");\n    if (results) results.classList.remove("open");\n\n    if (doc.targetId) {\n      const node = document.getElementById(doc.targetId);\n      if (node) {\n        node.scrollIntoView({ behavior: "smooth", block: "start" });\n        node.style.outline = "2px solid rgba(0,212,255,.72)";\n        node.style.boxShadow = "0 0 24px rgba(0,212,255,.22)";\n        setTimeout(() => {\n          node.style.outline = "";\n          node.style.boxShadow = "";\n        }, 2400);\n      }\n      return;\n    }\n\n    const stack = ensureRuntimeStack();\n    const panel = document.createElement("section");\n    panel.className = "claire-clean-stack-section";\n    panel.innerHTML = `\n      <div class="claire-clean-stack-header">\n        <div>\n          <div class="claire-clean-stack-kicker">Search Result</div>\n          <div class="claire-clean-stack-title">${escapeHtml(doc.title)}</div>\n          <div class="claire-clean-stack-subtitle">${escapeHtml(doc.path)}</div>\n        </div>\n      </div>\n      <pre style="white-space:pre-wrap; overflow-wrap:anywhere; max-height:52vh; overflow:auto;">${escapeHtml(JSON.stringify(doc.json ?? doc.text, null, 2))}</pre>\n    `;\n    stack.appendChild(panel);\n    panel.scrollIntoView({ behavior: "smooth", block: "start" });\n  }\n\n  function findPanelByHeading(text) {\n    const wanted = lower(text);\n    const headings = Array.from(document.querySelectorAll("h1,h2,h3,h4,.section-title,.surface-title,.panel-title"));\n    for (const heading of headings) {\n      if (!lower(heading.innerText || heading.textContent).includes(wanted)) continue;\n      return heading.closest("section,article,.dashboard-panel,.claire-panel,.surface,.portal,div");\n    }\n    return null;\n  }\n\n  function mainMount() {\n    return document.querySelector("main") || document.getElementById("app") || document.getElementById("workspace") || document.body;\n  }\n\n  function repairCommandPanel() {\n    const panel = findPanelByHeading("command");\n    if (!panel) return null;\n\n    panel.classList.add("claire-clean-command-repaired");\n\n    // Neutralize obvious clipped descendants.\n    Array.from(panel.querySelectorAll("*")).forEach((node) => {\n      const style = window.getComputedStyle(node);\n      const clipped = ["hidden", "auto", "scroll"].includes(style.overflowY) || ["hidden", "auto", "scroll"].includes(style.overflow);\n      if (clipped || style.maxHeight !== "none") {\n        node.style.overflow = "visible";\n        node.style.overflowY = "visible";\n        node.style.maxHeight = "none";\n      }\n    });\n\n    return panel;\n  }\n\n  function ensureRuntimeStack() {\n    let stack = document.getElementById("claire-clean-runtime-stack");\n    if (stack) return stack;\n\n    stack = document.createElement("div");\n    stack.id = "claire-clean-runtime-stack";\n\n    const commandPanel = repairCommandPanel();\n    if (commandPanel && commandPanel.parentElement) {\n      commandPanel.insertAdjacentElement("afterend", stack);\n    } else {\n      mainMount().prepend(stack);\n    }\n\n    return stack;\n  }\n\n  function metric(label, value, note = "") {\n    return `\n      <div class="claire-clean-card">\n        <div class="claire-clean-label">${escapeHtml(label)}</div>\n        <div class="claire-clean-value">${escapeHtml(value ?? "unknown")}</div>\n        ${note ? `<div class="claire-clean-note">${escapeHtml(note)}</div>` : ""}\n      </div>\n    `;\n  }\n\n  function pill(value) {\n    const status = compactStatus(value);\n    return `<span class="claire-clean-pill ${escapeHtml(status)}">${escapeHtml(value || "not_generated")}</span>`;\n  }\n\n  async function buildTruthData() {\n    const runtime = await fetchFirst([\n      "../../../exports/latest/dashboard_runtime_truth.json",\n      "exports/latest/dashboard_runtime_truth.json",\n      "runtime_truth_status.json",\n      "./runtime_truth_status.json"\n    ]);\n    const validation = await fetchFirst([\n      "../../../exports/latest/validation_authority_report.json",\n      "exports/latest/validation_authority_report.json",\n      "validation_authority_status.json",\n      "./validation_authority_status.json"\n    ]);\n    const evidence = await fetchFirst([\n      "../../../exports/latest/evidence_traceability_index.json",\n      "exports/latest/evidence_traceability_index.json",\n      "evidence_traceability_status.json",\n      "./evidence_traceability_status.json"\n    ]);\n    const memory = await fetchFirst([\n      "../../../exports/latest/verified_memory_gate_report.json",\n      "exports/latest/verified_memory_gate_report.json",\n      "verified_memory_status.json",\n      "./verified_memory_status.json"\n    ]);\n    const feedback = await fetchFirst([\n      "../../../exports/latest/recursive_feedback_gate_report.json",\n      "exports/latest/recursive_feedback_gate_report.json",\n      "recursive_feedback_status.json",\n      "./recursive_feedback_status.json"\n    ]);\n\n    return { runtime, validation, evidence, memory, feedback };\n  }\n\n  function runtimeValues(data) {\n    const r = data.runtime.json || {};\n    const run = section(r, "run_truth");\n    const route = section(r, "route_truth");\n    const term = section(r, "terminal_truth");\n    const stage = section(r, "stage_truth");\n    const validation = data.validation.json || {};\n    const memory = data.memory.json || {};\n\n    return {\n      runId: first(validation, ["run_id"], first(run, ["run_id", "id"], first(r, ["run_id"], "not_loaded"))),\n      route: first(validation, ["route_selected"], first(route, ["route_selected", "selected_route"], first(run, ["selected_route"], "not_loaded"))),\n      terminal: first(validation, ["terminal_state"], first(term, ["terminal_state", "state"], first(run, ["terminal_state"], "missing"))),\n      stages: first(stage, ["stages_total", "total_stages"], Array.isArray(stage.stages) ? stage.stages.length : "not_loaded"),\n      validationStatus: first(validation, ["validation_authority_status", "validation_status"], "not_generated"),\n      validationScore: first(validation, ["validation_score"], 0),\n      checks: `${first(validation, ["checks_passed"], 0)} pass / ${first(validation, ["checks_warning"], 0)} warn / ${first(validation, ["checks_failed"], 0)} fail`,\n      evidenceCount: first(data.evidence.json || {}, ["evidence_count"], first(validation.evidence_summary || {}, ["evidence_count"], 0)),\n      unsupported: first(data.evidence.json || {}, ["unsupported_count"], first(validation.evidence_summary || {}, ["unsupported_count"], 0)),\n      memoryStatus: first(memory, ["memory_status"], "not_generated"),\n      memoryEligible: first(memory, ["memory_eligible"], false) ? "eligible" : "blocked",\n      feedbackStatus: first(data.feedback.json || {}, ["feedback_status"], "not_generated"),\n      feedbackAllowed: first(data.feedback.json || {}, ["recursive_feedback_allowed"], false) ? "allowed" : "blocked"\n    };\n  }\n\n  async function renderRuntimeStack() {\n    removeConflictingUi();\n    const stack = ensureRuntimeStack();\n    const data = await buildTruthData();\n    const v = runtimeValues(data);\n\n    stack.innerHTML = `\n      <section class="claire-clean-stack-section">\n        <div class="claire-clean-stack-header">\n          <div>\n            <div class="claire-clean-stack-kicker">Runtime Truth Stack</div>\n            <div class="claire-clean-stack-title">Run, Route, Terminal, Stage, Validation</div>\n            <div class="claire-clean-stack-subtitle">\n              Stable replacement for the conflicting generated panels. It reads the same local truth/status files without inventing output.\n            </div>\n          </div>\n          ${pill(v.validationStatus)}\n        </div>\n        <div class="claire-clean-grid">\n          ${metric("Run", v.runId, data.runtime.path || "runtime truth source")}\n          ${metric("Route", v.route)}\n          ${metric("Terminal", v.terminal)}\n          ${metric("Stages", v.stages)}\n          ${metric("Validation score", `${v.validationScore}/100`)}\n          ${metric("Checks", v.checks)}\n          ${metric("Evidence", `${v.evidenceCount} item(s)`)}\n          ${metric("Unsupported", v.unsupported)}\n        </div>\n      </section>\n\n      <section class="claire-clean-stack-section purple">\n        <div class="claire-clean-stack-header">\n          <div>\n            <div class="claire-clean-stack-kicker">Verified Memory + Recursive Feedback</div>\n            <div class="claire-clean-stack-title">Memory Gate and Recursion Gate</div>\n            <div class="claire-clean-stack-subtitle">\n              No validation pass means no verified memory and no recursive feedback. This panel is gated report only.\n            </div>\n          </div>\n          ${pill(v.memoryStatus)}\n        </div>\n        <div class="claire-clean-grid">\n          ${metric("Memory status", v.memoryStatus)}\n          ${metric("Memory eligibility", v.memoryEligible)}\n          ${metric("Feedback status", v.feedbackStatus)}\n          ${metric("Feedback allowed", v.feedbackAllowed)}\n          ${metric("Validation dependency", v.validationStatus)}\n          ${metric("Storage mode", first(data.memory.json || {}, ["storage_mode"], "gated_report_only"))}\n          ${metric("Memory reason", (data.memory.json?.memory_reasons || ["Run verified memory command after validation."])[0], "",)}\n          ${metric("Feedback reason", (data.feedback.json?.feedback_reasons || ["Recursive feedback blocked until verified memory eligibility passes."])[0], "",)}\n        </div>\n      </section>\n    `;\n\n    collectVisibleDocs();\n  }\n\n  function installFocusToggle() {\n    const existing = document.getElementById("claire-view-mode-toggle");\n    if (existing) return;\n    const button = document.createElement("button");\n    button.id = "claire-view-mode-toggle";\n    button.className = "claire-view-mode-toggle";\n    button.type = "button";\n    button.textContent = "Focus View";\n    button.title = "Toggle focused dashboard view";\n    button.addEventListener("click", () => {\n      document.body.classList.toggle("claire-focus-mode");\n      button.textContent = document.body.classList.contains("claire-focus-mode") ? "Full View" : "Focus View";\n    });\n    document.body.appendChild(button);\n  }\n\n  async function boot() {\n    removeConflictingUi();\n    renderSearch();\n    installFocusToggle();\n    repairCommandPanel();\n    await renderRuntimeStack();\n\n    state.docs = [];\n    collectVisibleDocs();\n    await collectJsonDocs();\n\n    // Catch late-mounted conflicting panels from older bridge scripts.\n    setTimeout(async () => {\n      removeConflictingUi();\n      repairCommandPanel();\n      await renderRuntimeStack();\n    }, 900);\n\n    setTimeout(async () => {\n      removeConflictingUi();\n      repairCommandPanel();\n    }, 2200);\n  }\n\n  if (document.readyState === "loading") {\n    document.addEventListener("DOMContentLoaded", boot);\n  } else {\n    boot();\n  }\n})();\n', 'docs/dashboard/v17.62.5_dashboard_conflict_cleanup.md': '# Claire v17.62.5 — Dashboard Conflict Cleanup + Stable Runtime Stack\n\n## Purpose\n\nThe screenshots after v17.62.4 show that multiple dashboard-injection layers are fighting each other:\n\n- old floating search overlay returned\n- validation bridge panel overlaps command\n- memory bridge panel overlaps validation\n- proof/status rail cuts across the workspace\n- command cards are clipped by older internal scroll containers\n\nv17.62.5 cleans this up by removing old conflicting dashboard injections and rendering a single stable runtime-truth stack.\n\n## What changed\n\nInstalled:\n\n```text\nsrc/frontend/command_center/modern/claire_dashboard_reset_v17_62_5.css\nsrc/frontend/command_center/modern/claire_dashboard_reset_v17_62_5.js\n```\n\nPatched:\n\n```text\nsrc/frontend/command_center/modern/index.html\n```\n\nThe installer also removes old conflicting v17.62-series link/script tags from the dashboard HTML before injecting the clean reset layer.\n\n## Dashboard behavior\n\n- Search is embedded in the Claire identity/sidebar area.\n- Old floating search shells are removed.\n- Old generated validation/memory panels are hidden.\n- New clean runtime stack shows run, route, terminal, stages, validation, evidence, memory, and recursion.\n- Runtime truth remains honest; missing data is shown as not_loaded, missing, blocked, or not_generated.\n\n## Scope\n\nNo runtime logic changed.\nNo validation logic changed.\nNo memory logic changed.\nThis is a dashboard conflict cleanup layer.\n', 'docs/update_packs/v17.62.5_dashboard_cleanup_pack.md': '# v17.62.5 Dashboard Cleanup Pack\n\n## Architecture section covered\n\n- Operating Environment usability\n- Runtime truth display\n- Validation authority display\n- Verified memory display\n- Dashboard search command layer\n\n## Verification\n\nAfter installing:\n\n1. Hard refresh with Ctrl+F5.\n2. Confirm there is only one search bar.\n3. Confirm the search bar sits in the left identity area.\n4. Confirm the old descriptive text is gone.\n5. Confirm old overlapping validation/memory panels are gone.\n6. Confirm a new clean Runtime Truth Stack appears below Command.\n7. Confirm missing runtime data is displayed honestly.\n', 'data/build_manifests/v17.62.5_dashboard_conflict_cleanup_manifest.json': '{\n  "version": "17.62.5",\n  "name": "Dashboard Conflict Cleanup + Stable Runtime Stack",\n  "build_type": "dashboard_cleanup_hotfix",\n  "purpose": "Remove v17.62-series conflicting dashboard injections and render one stable runtime-truth stack.",\n  "depends_on": [\n    "v17.62.4 Workspace Stack Fix"\n  ],\n  "installed_files": [\n    "docs/dashboard/v17.62.5_dashboard_conflict_cleanup.md",\n    "docs/update_packs/v17.62.5_dashboard_cleanup_pack.md",\n    "src/frontend/command_center/modern/claire_dashboard_reset_v17_62_5.css",\n    "src/frontend/command_center/modern/claire_dashboard_reset_v17_62_5.js"\n  ],\n  "safety": {\n    "rollback_backups": true,\n    "launcher_path_preserved": "src/frontend/command_center/modern/index.html",\n    "runtime_logic_unchanged": true,\n    "validation_logic_unchanged": true,\n    "memory_logic_unchanged": true,\n    "old_dashboard_injections_removed": true,\n    "no_fake_data": true\n  }\n}\n'}

CSS_FILE = "claire_dashboard_reset_v17_62_5.css"
JS_FILE = "claire_dashboard_reset_v17_62_5.js"

CONFLICTING_ASSETS = [
    "claire_portal_responsive_layout.css",
    "claire_dashboard_decongestion.css",
    "claire_search_relocation.css",
    "claire_overlap_fix.css",
    "claire_workspace_stack_fix.css",
    "claire_dashboard_search.js",
    "claire_workspace_stack_fix.js",
    "claire_validation_authority.js",
    "claire_verified_memory.js",
]

def utc_stamp() -> str:
    return datetime.utcnow().strftime("%Y%m%d_%H%M%S")

def project_root() -> Path:
    return Path.cwd().resolve()

def backup_existing(root: Path, relative_path: str, backup_root: Path) -> None:
    target = root / relative_path
    if not target.exists():
        return
    backup_path = backup_root / relative_path
    backup_path.parent.mkdir(parents=True, exist_ok=True)
    if target.is_file():
        shutil.copy2(target, backup_path)
    elif target.is_dir():
        if backup_path.exists():
            shutil.rmtree(backup_path)
        shutil.copytree(target, backup_path)

def write_text(root: Path, relative_path: str, content: str, backup_root: Path) -> None:
    target = root / relative_path
    backup_existing(root, relative_path, backup_root)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")

def remove_asset_tags(html: str, asset_name: str) -> str:
    # Remove stylesheet tags containing the asset.
    html = re.sub(
        r'\s*<link\b[^>]*href=["\'][^"\']*' + re.escape(asset_name) + r'[^"\']*["\'][^>]*>\s*',
        "\n",
        html,
        flags=re.IGNORECASE,
    )
    # Remove script tags containing the asset.
    html = re.sub(
        r'\s*<script\b[^>]*src=["\'][^"\']*' + re.escape(asset_name) + r'[^"\']*["\'][^>]*>\s*</script>\s*',
        "\n",
        html,
        flags=re.IGNORECASE,
    )
    return html

def patch_index_html(root: Path, backup_root: Path) -> bool:
    index_rel = "src/frontend/command_center/modern/index.html"
    index_path = root / index_rel
    if not index_path.exists():
        return False

    html = index_path.read_text(encoding="utf-8", errors="ignore")
    original = html

    for asset in CONFLICTING_ASSETS:
        html = remove_asset_tags(html, asset)

    # Remove prior v17.62.5 tag if present, then inject once at the end.
    html = remove_asset_tags(html, CSS_FILE)
    html = remove_asset_tags(html, JS_FILE)

    css_tag = '\n<link rel="stylesheet" href="claire_dashboard_reset_v17_62_5.css">\n'
    js_tag = '\n<script src="claire_dashboard_reset_v17_62_5.js"></script>\n'

    if "</head>" in html:
        html = html.replace("</head>", css_tag + "</head>", 1)
    else:
        html = css_tag + html

    if "</body>" in html:
        html = html.replace("</body>", js_tag + "</body>", 1)
    else:
        html = html + js_tag

    if html != original:
        backup_existing(root, index_rel, backup_root)
        index_path.write_text(html, encoding="utf-8")

    return True

def write_install_record(root: Path, backup_root: Path, index_patched: bool) -> None:
    record = {
        "version": VERSION,
        "build_name": BUILD_NAME,
        "installed_at_utc": datetime.utcnow().isoformat() + "Z",
        "project_root": str(root),
        "backup_root": str(backup_root),
        "index_patched": index_patched,
        "files_written": sorted(FILES.keys()),
        "removed_conflicting_assets_from_index": CONFLICTING_ASSETS,
        "notes": [
            "Removes conflicting v17.62-series dashboard scripts/styles from index.html.",
            "Adds one reset CSS and one reset JS.",
            "Hides old dynamic validation/memory bridge panels and renders stable runtime truth stack.",
            "Runtime, validation, and memory logic unchanged."
        ]
    }
    record_path = root / "data" / "build_manifests" / "v17.62.5_install_record.json"
    record_path.parent.mkdir(parents=True, exist_ok=True)
    record_path.write_text(json.dumps(record, indent=2) + "\n", encoding="utf-8")

def main() -> None:
    root = project_root()
    backup_root = root / "backups" / f"claire_v17_62_5_{utc_stamp()}"
    backup_root.mkdir(parents=True, exist_ok=True)

    for relative_path, content in FILES.items():
        write_text(root, relative_path, content, backup_root)

    index_patched = patch_index_html(root, backup_root)
    write_install_record(root, backup_root, index_patched)

    print("=" * 72)
    print(f"Claire v{VERSION} installed: {BUILD_NAME}")
    print("=" * 72)
    print(f"Project root: {root}")
    print(f"Backups:      {backup_root}")
    print("")
    print("Cleaned conflicting dashboard layers and installed one stable reset layer.")
    print("")
    print("Removed from index.html when present:")
    for asset in CONFLICTING_ASSETS:
        print(f"  - {asset}")
    print("")
    print("Added:")
    print(f"  - {CSS_FILE}")
    print(f"  - {JS_FILE}")
    print("")
    print("Hard refresh the dashboard with Ctrl+F5.")
    print("=" * 72)

if __name__ == "__main__":
    main()
